import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Layout from '../components/4_unity/Layout';
import Header from '../components/3_organism/Header';
import FooterSection from '../components/3_organism/FooterSection';
import SectionTitle from '../components/1_atoms/SectionTitle';
import CharacterCreationModal from '../components/3_organism/CharacterCreationModal';
import { useAuth } from '../hooks/useAuth';
import apiClient from '../api/apiClient';

function AccountPage() {
  const { user, logout, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [characters, setCharacters] = useState([]);
  const [selectedCharacter, setSelectedCharacter] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [sessionLoading, setSessionLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [createError, setCreateError] = useState(null);

  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
    }
  }, [isAuthenticated, navigate]);

  useEffect(() => {
    setCharacters([
      { id: 1, fullName: 'Сохранитель' },
      { id: 2, fullName: 'Страховщик' },
      { id: 3, fullName: 'Инвестор' },
    ]);
  }, []);

  const openCreateModal = () => {
    setCreateError(null);
    setModalOpen(true);
  };

  const closeCreateModal = () => {
    setModalOpen(false);
  };

  const handleGameStart = async ({ fullName }) => {
    setCreateError(null);
    setSessionLoading(true);

    try {
      const sessionResponse = await apiClient.post('/v1/session_game', {
        fullName,
      });
      const newSessionGameID =
        sessionResponse.id ||
        sessionResponse.sessionGameID ||
        sessionResponse.sessionId ||
        sessionResponse.session_id;

      if (!newSessionGameID) {
        throw new Error('Не удалось получить идентификатор сессии');
      }

      navigate(`/game/${newSessionGameID}`);
    } catch (err) {
      setCreateError(err.message || 'Ошибка при создании персонажа');
    } finally {
      setSessionLoading(false);
    }
  };

  const handleCharacterSelect = async (character) => {
    setSelectedCharacter(character);
    setError(null);
    setLoading(true);

    try {
      const sessionResponse = await apiClient.post('/v1/session_game', {
        fullName: character.fullName,
      });

      const newSessionGameID =
        sessionResponse.id ||
        sessionResponse.sessionGameID ||
        sessionResponse.sessionId ||
        sessionResponse.session_id;

      if (!newSessionGameID) {
        throw new Error('Не удалось получить идентификатор сессии');
      }

      navigate(`/game/${newSessionGameID}`);
    } catch (err) {
      setError(err.message || 'Не удалось начать игру');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  if (!isAuthenticated) {
    return null;
  }

  return (
    <Layout>
      <Header />
      <main className="account-page">
        <section className="account-hero">
          <div className="account-hero__top">
            <div>
              <h1>{user?.name} {user?.surname}</h1>
              <p className="account-subtitle">Добро пожаловать в игру. Выбери готового персонажа или создай своего героя.</p>
            </div>
            <div className="account-actions">
              <button className="button button--secondary" onClick={openCreateModal}>
                Создать персонажа
              </button>
              <button className="button button--primary" onClick={handleLogout}>
                Выйти
              </button>
            </div>
          </div>

          <div className="account-hero__title">
            <h2>Выбери своего персонажа</h2>
          </div>

          {error && <div className="auth-error">{error}</div>}

          <div className="characters-list">
            {characters.map((character) => (
              <button
                key={character.id}
                type="button"
                className={`character-card ${selectedCharacter?.id === character.id ? 'character-card--active' : ''}`}
                onClick={() => handleCharacterSelect(character)}
                disabled={loading}
              >
                <div className="character-card__info">
                  <span className="character-card__name">{character.fullName}</span>
                  <p>Уникальный путь в мире страхования</p>
                </div>
                {loading && selectedCharacter?.id === character.id && (
                  <div className="character-card__loading">Загрузка...</div>
                )}
              </button>
            ))}
          </div>

          <CharacterCreationModal
            visible={modalOpen}
            onClose={closeCreateModal}
            onCreate={handleGameStart}
            loading={sessionLoading}
            error={createError}
          />
        </section>
      </main>
      <FooterSection />
    </Layout>
  );
}

export default AccountPage;
